import asyncio
import json
from typing import Optional, List, Dict, Any
from pydantic import BaseModel
from openai import AsyncOpenAI, RateLimitError
import os
from datetime import datetime

class AnalysisResult(BaseModel):
    """Structured analysis result from LLM"""
    match_summary: str
    key_performances: List[str]
    turning_points: List[str]
    strategic_insights: str
    player_comparisons: Dict[str, str]
    match_winner_factors: List[str]
    prediction_for_next_match: Optional[str] = None

class CricketLLMAnalyzer:
    """Orchestrates LLM-based cricket match analysis with prompt engineering"""

    def __init__(self, api_key: Optional[str] = None, model: str = "gpt-4-turbo-preview"):
        self.api_key = api_key or os.getenv("OPENAI_API_KEY")
        self.model = model
        self.client = AsyncOpenAI(api_key=self.api_key)
        self.max_retries = 3
        self.base_retry_delay = 1  # seconds

    def _build_context_prompt(self, scorecard: Dict[str, Any]) -> str:
        """Build initial context-setting prompt from scorecard data"""
        return f"""You are an expert cricket analyst. Analyze this match carefully:

Match Details:
- Format: {scorecard['match_format']}
- Venue: {scorecard['venue']}
- Date: {scorecard['date_played']}
- Toss: {scorecard['toss_winner']} won and elected to {scorecard['toss_decision']}

Match Result: {scorecard['match_result']}

Team 1 ({scorecard['host_team']}):
- Total: {scorecard['team1_total_runs']}/{scorecard['team1_total_wickets']} in {scorecard['team1_overs_faced']} overs
- Run Rate: {scorecard.get('team1_run_rate', 0):.2f}

Team 2 ({scorecard['away_team']}):
- Total: {scorecard['team2_total_runs']}/{scorecard['team2_total_wickets']} in {scorecard['team2_overs_faced']} overs
- Run Rate: {scorecard.get('team2_run_rate', 0):.2f}

Provide a concise match summary (2-3 sentences) identifying the overall narrative of this match."""

    def _build_performance_prompt(self, top_batsmen: List[Dict], top_bowlers: List[Dict]) -> str:
        """Build prompt to analyze individual performances"""
        batsmen_str = "\n".join([f"- {b['name']}: {b['runs']} runs off {b['balls']} balls (SR: {b['strike_rate']:.2f})" 
                                  for b in top_batsmen[:3]])
        bowlers_str = "\n".join([f"- {b['name']}: {b['wickets']}-{b['runs']} ({b['overs']} overs, ER: {b['economy']:.2f})" 
                                  for b in top_bowlers[:3]])

        return f"""Based on the match context, analyze these key individual performances:

Top Batsmen:
{batsmen_str}

Top Bowlers:
{bowlers_str}

For each, identify what made their performance standout and how it impacted the match result. Format as a list of 3-4 specific insights."""

    def _build_strategy_prompt(self) -> str:
        """Build prompt to analyze match strategy and tactics"""
        return """Analyze the strategic decisions that defined this match:
1. How effective was the powerplay batting strategy for the chasing team (if applicable)?
2. Did the bowling attack exploit the pitch conditions appropriately?
3. What were the critical momentum shifts, and which team caused them?
4. Were there any questionable tactical decisions that changed the match outcome?

Provide insights in 2-3 focused paragraphs."""

    async def _call_llm_with_retry(self, prompt: str, temperature: float = 0.7) -> str:
        """Call LLM with exponential backoff retry logic"""
        for attempt in range(self.max_retries):
            try:
                response = await self.client.chat.completions.create(
                    model=self.model,
                    messages=[
                        {"role": "system", "content": "You are an expert cricket analyst with deep knowledge of match dynamics, player strengths, and strategic nuances."},
                        {"role": "user", "content": prompt}
                    ],
                    temperature=temperature,
                    max_tokens=1000
                )
                return response.choices[0].message.content

            except RateLimitError as e:
                if attempt < self.max_retries - 1:
                    wait_time = self.base_retry_delay * (2 ** attempt)
                    print(f"Rate limited. Waiting {wait_time} seconds before retry...")
                    await asyncio.sleep(wait_time)
                else:
                    raise Exception(f"Failed after {self.max_retries} retries: {str(e)}")

            except Exception as e:
                if attempt < self.max_retries - 1:
                    await asyncio.sleep(1)
                else:
                    raise

        return ""

    def _parse_analysis_response(self, context: str, performance: str, strategy: str) -> AnalysisResult:
        """Parse and structure LLM responses into AnalysisResult"""
        # In production, you might use JSON mode or additional validation
        return AnalysisResult(
            match_summary=context[:200] if context else "",
            key_performances=[line.strip() for line in performance.split("\n") if line.strip() and line.startswith("-")][:4],
            turning_points=[],
            strategic_insights=strategy,
            player_comparisons={},
            match_winner_factors=[],
            prediction_for_next_match=None
        )

    async def analyze_match(self, scorecard_dict: Dict[str, Any], 
                           top_batsmen: List[Dict], 
                           top_bowlers: List[Dict]) -> AnalysisResult:
        """Execute full multi-turn analysis pipeline"""
        try:
            # Step 1: Get match context and summary
            context_prompt = self._build_context_prompt(scorecard_dict)
            context_response = await self._call_llm_with_retry(context_prompt, temperature=0.5)

            # Step 2: Analyze key individual performances
            performance_prompt = self._build_performance_prompt(top_batsmen, top_bowlers)
            performance_response = await self._call_llm_with_retry(performance_prompt, temperature=0.6)

            # Step 3: Analyze strategic elements
            strategy_prompt = self._build_strategy_prompt()
            strategy_response = await self._call_llm_with_retry(strategy_prompt, temperature=0.7)

            # Parse and structure all responses
            analysis = self._parse_analysis_response(context_response, performance_response, strategy_response)
            return analysis

        except Exception as e:
            print(f"Analysis error: {str(e)}")
            raise

# src/cricket_match_analyzer_pipeline.py
import json
import asyncio
from typing import Dict, List, Optional, Tuple
from datetime import datetime
from pathlib import Path
import hashlib

from src.models.cricket_entities import (
    CricketMatch, MatchScorecard, BattingInnings, BowlingSpell, CricketPlayer
)
from src.analyzers.llm_cricket_analyzer import CricketLLMAnalyzer, AnalysisResult

class CricketMatchAnalysisPipeline:
    """Full end-to-end pipeline for cricket match analysis using LLMs"""

    def __init__(self, cache_dir: str = "./cache", api_key: Optional[str] = None):
        self.analyzer = CricketLLMAnalyzer(api_key=api_key)
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(exist_ok=True)
        self.validation_log = []

    def _load_match_data(self, json_path: str) -> Dict:
        """Load and parse match data from JSON file"""
        try:
            with open(json_path, 'r') as f:
                data = json.load(f)
            return data
        except FileNotFoundError:
            raise ValueError(f"Match data file not found: {json_path}")
        except json.JSONDecodeError:
            raise ValueError(f"Invalid JSON in match data file: {json_path}")

    def _validate_match_data(self, data: Dict) -> Tuple[bool, List[str]]:
        """Validate match data against schema"""
        errors = []

        # Validate required fields
        required_fields = ['match_id', 'match_format', 'venue', 'host_team', 'away_team']
        for field in required_fields:
            if field not in data:
                errors.append(f"Missing required field: {field}")

        # Validate team totals
        if 'team1_total_runs' not in data or 'team1_total_wickets' not in data:
            errors.append("Missing team1 scorecard data")
        if 'team2_total_runs' not in data or 'team2_total_wickets' not in data:
            errors.append("Missing team2 scorecard data")

        # Validate batting innings structure
        if 'team1_batting' in data and isinstance(data['team1_batting'], list):
            for idx, innings in enumerate(data['team1_batting']):
                if not all(k in innings for k in ['player_name', 'runs', 'balls_faced']):
                    errors.append(f"Incomplete batting record at index {idx}")

        # Validate bowling spells structure
        if 'team1_bowling' in data and isinstance(data['team1_bowling'], list):
            for idx, spell in enumerate(data['team1_bowling']):
                if not all(k in spell for k in ['player_name', 'wickets', 'runs_conceded']):
                    errors.append(f"Incomplete bowling record at index {idx}")

        return len(errors) == 0, errors

    def _enrich_scorecard_metrics(self, data: Dict) -> Dict:
        """Calculate and add derived metrics to match data"""
        enriched = data.copy()

        # Calculate team1 run rate
        if enriched.get('team1_overs_faced', 0) > 0:
            enriched['team1_run_rate'] = (
                enriched['team1_total_runs'] / enriched['team1_overs_faced']
            )
        else:
            enriched['team1_run_rate'] = 0.0

        # Calculate team2 run rate
        if enriched.get('team2_overs_faced', 0) > 0:
            enriched['team2_run_rate'] = (
                enriched['team2_total_runs'] / enriched['team2_overs_faced']
            )
        else:
            enriched['team2_run_rate'] = 0.0

        # Extract top batsmen and bowlers
        team1_batting = enriched.get('team1_batting', [])
        top_batsmen = sorted(
            [{
                'name': b['player_name'],
                'runs': b['runs'],
                'balls': b['balls_faced'],
                'strike_rate': (b['runs'] / b['balls_faced'] * 100) if b['balls_faced'] > 0 else 0
            } for b in team1_batting],
            key=lambda x: x['runs'],
            reverse=True
        )[:5]

        team1_bowling = enriched.get('team1_bowling', [])
        top_bowlers = sorted(
            [{
                'name': b['player_name'],
                'wickets': b['wickets'],
                'runs': b['runs_conceded'],
                'overs': b['overs_bowled'],
                'economy': (b['runs_conceded'] / b['overs_bowled']) if b['overs_bowled'] > 0 else 0
            } for b in team1_bowling],
            key=lambda x: x['wickets'],
            reverse=True
        )[:5]

        enriched['top_batsmen'] = top_batsmen
        enriched['top_bowlers'] = top_bowlers

        return enriched

    def _get_cache_key(self, match_id: str) -> str:
        """Generate cache key for match analysis"""
        return hashlib.sha256(match_id.encode()).hexdigest()[:16]

    def _load_cached_analysis(self, match_id: str) -> Optional[Dict]:
        """Load cached analysis if available"""
        cache_file = self.cache_dir / f"{self._get_cache_key(match_id)}.json"
        if cache_file.exists():
            try:
                with open(cache_file, 'r') as f:
                    return json.load(f)
            except:
                return None
        return None

    def _save_cached_analysis(self, match_id: str, analysis: AnalysisResult) -> None:
        """Save analysis to cache"""
        cache_file = self.cache_dir / f"{self._get_cache_key(match_id)}.json"
        try:
            with open(cache_file, 'w') as f:
                json.dump(analysis.model_dump(), f, indent=2)
        except Exception as e:
            print(f"Cache save error: {e}")

    async def run_full_analysis(self, json_path: str, use_cache: bool = True) -> Dict:
        """Execute complete analysis pipeline"""
        # Load match data
        print(f"[1/5] Loading match data from {json_path}...")
        match_data = self._load_match_data(json_path)

        # Validate data
        print("[2/5] Validating match data schema...")
        is_valid, errors = self._validate_match_data(match_data)
        if not is_valid:
            print(f"Validation errors: {errors}")
            raise ValueError(f"Match data validation failed: {errors}")

        # Check cache
        match_id = match_data.get('match_id')
        if use_cache:
            cached = self._load_cached_analysis(match_id)
            if cached:
                print(f"[3/5] Using cached analysis for {match_id}")
                return {"match_id": match_id, "analysis": cached, "from_cache": True}

        # Enrich metrics
        print("[3/5] Enriching scorecard with calculated metrics...")
        enriched_data = self._enrich_scorecard_metrics(match_data)

        # Run LLM analysis
        print("[4/5] Running LLM-based match analysis (this may take 20-30 seconds)...")
        analysis = await self.analyzer.analyze_match(
            enriched_data,
            enriched_data.get('top_batsmen', []),
            enriched_data.get('top_bowlers', [])
        )

        # Save cache and return
        print("[5/5] Saving analysis to cache...")
        self._save_cached_analysis(match_id, analysis)

        return {
            "match_id": match_id,
            "analysis": analysis.model_dump(),
            "from_cache": False,
            "timestamp": datetime.now().isoformat()
        }

    def format_analysis_report(self, result: Dict) -> str:
        """Format analysis into readable report"""
        analysis = result.get('analysis', {})
        report = f"""
╔════════════════════════════════════════════════════════════╗
║          CRICKET MATCH ANALYSIS REPORT                      ║
║          Match ID: {result.get('match_id', 'N/A'):<32}║
╚════════════════════════════════════════════════════════════╝

📊 MATCH SUMMARY
{'-' * 60}
{analysis.get('match_summary', 'N/A')}

⭐ KEY PERFORMANCES
{'-' * 60}
"""
        for perf in analysis.get('key_performances', []):
            report += f"• {perf}\n"

        report += f"""
🎯 STRATEGIC INSIGHTS
{'-' * 60}
{analysis.get('strategic_insights', 'N/A')}

📈 MATCH-WINNING FACTORS
{'-' * 60}
"""
        for factor in analysis.get('match_winner_factors', []):
            report += f"• {factor}\n"

        if result.get('from_cache'):
            report += "\n[Analysis loaded from cache]\n"

        return report
